package org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni;

import static java.lang.foreign.ValueLayout.JAVA_BYTE;
import static java.lang.foreign.ValueLayout.JAVA_INT_UNALIGNED;
import static java.lang.foreign.ValueLayout.JAVA_LONG_UNALIGNED;

import java.lang.foreign.MemorySegment;

import org.apache.datasketches.common.SketchesArgumentException;

/** Serialization for compact OmniSketch images. */
final class OmniSketchSerializationUtil {
	private static final int CELL_HEADER_BYTES = Long.BYTES + Integer.BYTES + Integer.BYTES;

	private OmniSketchSerializationUtil() {
	}

	static int getSerializedSize(final OmniSketch sketch) {
		long size = PreambleUtil.PREAMBLE_BYTES;
		for (int row = 0; row < sketch.getNumRows(); row++) {
			for (int column = 0; column < sketch.getWidth(); column++) {
				size += CELL_HEADER_BYTES + (long) sketch.getCell(row, column).getRetainedEntries() * Long.BYTES;
				if (size > Integer.MAX_VALUE) {
					throw new SketchesArgumentException("Serialized OmniSketch image exceeds maximum Java array size");
				}
			}
		}
		return (int) size;
	}

	static byte[] toByteArray(final OmniSketch sketch) {
		final int bytes = getSerializedSize(sketch);
		final byte[] out = new byte[bytes];
		writeSketch(sketch, MemorySegment.ofArray(out), true);
		return out;
	}

	static void writeSketch(final OmniSketch sketch, final MemorySegment dstSeg, final boolean readOnly) {
		final int bytes = getSerializedSize(sketch);
		PreambleUtil.insertPreamble(dstSeg, sketch, sketch.getRetainedEntries(), bytes, readOnly);
		long offset = PreambleUtil.PREAMBLE_BYTES;
		for (int row = 0; row < sketch.getNumRows(); row++) {
			for (int column = 0; column < sketch.getWidth(); column++) {
				offset = writeCell(dstSeg, offset, sketch.getCell(row, column));
			}
		}
		if (offset != bytes) {
			throw new SketchesArgumentException("Internal OmniSketch serialization size mismatch");
		}
	}

	static HeapCompactOmniSketch heapify(final MemorySegment srcSeg) {
		PreambleUtil.checkPreamble(srcSeg);
		final int lgWidth = PreambleUtil.extractLgWidth(srcSeg);
		final int numRows = PreambleUtil.extractNumRows(srcSeg);
		final int nominalEntries = PreambleUtil.extractNominalEntries(srcSeg);
		final long seed = PreambleUtil.extractSeed(srcSeg);
		final long totalUpdates = PreambleUtil.extractTotalUpdates(srcSeg);
		final int retainedEntries = PreambleUtil.extractRetainedEntries(srcSeg);
		final int width = 1 << lgWidth;
		final OmniSketchCell[][] cells = new OmniSketchCell[numRows][width];
		long offset = PreambleUtil.PREAMBLE_BYTES;
		for (int row = 0; row < numRows; row++) {
			for (int column = 0; column < width; column++) {
				final ReadCellResult result = readCellAt(srcSeg, offset, nominalEntries);
				cells[row][column] = result.cell.heapCopy();
				offset = result.nextOffset;
			}
		}
		final int serializationBytes = PreambleUtil.extractSerializationBytes(srcSeg);
		if (offset != serializationBytes) {
			throw new SketchesArgumentException("OmniSketch image size mismatch: expected " + serializationBytes
					+ " bytes but decoded " + offset);
		}
		return new HeapCompactOmniSketch(lgWidth, numRows, nominalEntries, seed, totalUpdates, retainedEntries, cells);
	}

	static WrappedCompactOmniSketch wrap(final MemorySegment srcSeg) {
		PreambleUtil.checkPreamble(srcSeg);
		final int bytes = PreambleUtil.extractSerializationBytes(srcSeg);
		validateCellLayout(srcSeg, bytes);
		return new WrappedCompactOmniSketch(srcSeg.asSlice(0, bytes));
	}

	static OmniSketchCell readCell(final MemorySegment seg, final int row, final int column) {
		PreambleUtil.checkPreamble(seg);
		final int numRows = PreambleUtil.extractNumRows(seg);
		final int lgWidth = PreambleUtil.extractLgWidth(seg);
		final int width = 1 << lgWidth;
		if (row < 0 || row >= numRows || column < 0 || column >= width) {
			throw new SketchesArgumentException(
					"OmniSketch cell index out of range: row=" + row + ", column=" + column);
		}
		final long target = (long) row * width + column;
		long offset = PreambleUtil.PREAMBLE_BYTES;
		for (long i = 0; i < target; i++) {
			offset = skipCell(seg, offset, PreambleUtil.extractNominalEntries(seg));
		}
		return readCellAt(seg, offset, PreambleUtil.extractNominalEntries(seg)).cell;
	}

	private static long writeCell(final MemorySegment seg, long offset, final OmniSketchCell cell) {
		seg.set(JAVA_LONG_UNALIGNED, offset, cell.getCount());
		offset += Long.BYTES;
		seg.set(JAVA_INT_UNALIGNED, offset, cell.getRetainedEntries());
		offset += Integer.BYTES;
		seg.set(JAVA_INT_UNALIGNED, offset, 0);
		offset += Integer.BYTES;
		final long[] hashes = cell.copyHashes();
		for (final long hash : hashes) {
			seg.set(JAVA_LONG_UNALIGNED, offset, hash);
			offset += Long.BYTES;
		}
		return offset;
	}

	private static long skipCell(final MemorySegment seg, final long offset, final int nominalEntries) {
		if (offset + CELL_HEADER_BYTES > seg.byteSize()) {
			throw new SketchesArgumentException("Truncated OmniSketch cell header");
		}
		final int retained = seg.get(JAVA_INT_UNALIGNED, offset + Long.BYTES);
		checkRetained(retained, nominalEntries);
		final long nextOffset = offset + CELL_HEADER_BYTES + (long) retained * Long.BYTES;
		if (nextOffset > seg.byteSize()) {
			throw new SketchesArgumentException("Truncated OmniSketch cell sample");
		}
		return nextOffset;
	}

	private static ReadCellResult readCellAt(final MemorySegment seg, long offset, final int nominalEntries) {
		if (offset + CELL_HEADER_BYTES > seg.byteSize()) {
			throw new SketchesArgumentException("Truncated OmniSketch cell header");
		}
		final long count = seg.get(JAVA_LONG_UNALIGNED, offset);
		offset += Long.BYTES;
		final int retained = seg.get(JAVA_INT_UNALIGNED, offset);
		offset += Integer.BYTES;
		seg.get(JAVA_INT_UNALIGNED, offset); // reserved
		offset += Integer.BYTES;
		checkRetained(retained, nominalEntries);
		if (offset + (long) retained * Long.BYTES > seg.byteSize()) {
			throw new SketchesArgumentException("Truncated OmniSketch cell sample");
		}
		final long[] hashes = new long[retained];
		for (int i = 0; i < retained; i++) {
			hashes[i] = seg.get(JAVA_LONG_UNALIGNED, offset);
			offset += Long.BYTES;
		}
		return new ReadCellResult(new OmniSketchCell(nominalEntries, count, hashes, retained), offset);
	}

	private static void validateCellLayout(final MemorySegment seg, final int serializationBytes) {
		long offset = PreambleUtil.PREAMBLE_BYTES;
		final int numRows = PreambleUtil.extractNumRows(seg);
		final int width = 1 << PreambleUtil.extractLgWidth(seg);
		final int nominalEntries = PreambleUtil.extractNominalEntries(seg);
		for (int row = 0; row < numRows; row++) {
			for (int column = 0; column < width; column++) {
				offset = skipCell(seg, offset, nominalEntries);
			}
		}
		if (offset != serializationBytes) {
			throw new SketchesArgumentException("OmniSketch image size mismatch: expected " + serializationBytes
					+ " bytes but decoded " + offset);
		}
	}

	private static void checkRetained(final int retained, final int nominalEntries) {
		if (retained < 0 || retained > nominalEntries) {
			throw new SketchesArgumentException("Invalid OmniSketch cell retained entry count: " + retained);
		}
	}

	private static final class ReadCellResult {
		final OmniSketchCell cell;
		final long nextOffset;

		ReadCellResult(final OmniSketchCell cell, final long nextOffset) {
			this.cell = cell;
			this.nextOffset = nextOffset;
		}
	}
}
